}

if ((!bodyObj || Object.keys(bodyObj).length === 0) && query.body) {
  bodyObj = query.body;
}

  // se query foi usada como envelope errado, pega só queryParams reais
  if (query.query.url || query.query.method || query.query.headers || query.query.body || query.query.queryParams) {
    queryObj = query.query.queryParams ?? null;
  }
}

if (!rawUrl) {
  return JSON.stringify({
    success: false,
    error: "Campo 'url' é obrigatório."
  });
}

const VALID_METHODS = ["GET", "POST", "PUT", "PATCH", "DELETE"];
if (!VALID_METHODS.includes(method)) {
  return JSON.stringify({
    success: false,
    error: `Método '${method}' inválido. Use: ${VALID_METHODS.join(", ")}.`
  });
}

// validações extras para métodos que exigem payload
if (["POST", "PUT", "PATCH"].includes(method)) {
  if (!headersObj || typeof headersObj !== "object" || Object.keys(headersObj).length === 0) {
    return JSON.stringify({
      success: false,
      error: `Para método ${method}, o campo 'headers' é obrigatório.`
    });
  }

  if (!bodyObj || typeof bodyObj !== "object" || Object.keys(bodyObj).length === 0) {
    return JSON.stringify({
      success: false,
      error: `Para método ${method}, o campo 'body' é obrigatório.`
    });
  }
}

function buildQs(params) {
  if (!params || typeof params !== "object" || Object.keys(params).length === 0) {
    return undefined;
  }
  return params;
}

function buildHeaders(h) {
  if (!h || typeof h !== "object" || Object.keys(h).length === 0) {
    return undefined;
  }
  return { ...h };
}

function buildBody(b, method) {
  if (["GET", "DELETE"].includes(method)) return undefined;
  if (b === null || b === undefined) return undefined;
  if (typeof b === "object" && Object.keys(b).length === 0) return undefined;
  if (typeof b === "string" && b.trim() === "") return undefined;
  return b;
}

// garante que qualquer retorno vire JSON válido
function normalizeData(raw) {
  if (raw === null || raw === undefined) return null;

  if (typeof raw === "object") return raw;

  if (typeof raw === "string") {
    try {
      return JSON.parse(raw);
    } catch {
      return { message: raw };
    }
  }

  return { value: raw };
}

const qs      = buildQs(queryObj);
const headers = buildHeaders(headersObj);
const body    = buildBody(bodyObj, method);

try {
  const options = {
    method,
    url: rawUrl,
    returnFullResponse: true,
    json: true,
  };

  if (headers) options.headers = headers;
  if (qs) options.qs = qs;
  if (body !== undefined) options.body = body;

  const response = await this.helpers.httpRequest(options);

  return JSON.stringify({
    success: response.statusCode >= 200 && response.statusCode < 300,
    status: response.statusCode,
    data: normalizeData(response.body),
  });

} catch (err) {
  return JSON.stringify({
    success: false,
    status: err.response?.statusCode ?? null,
    error: err.message,
    data: normalizeData(err.response?.body ?? null),
  });
}

